final:
module RefModule(
    input               clk,
    input               rst,

    output reg [2:0]    johnson_code
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        johnson_code <= 3'b000;
    else
        johnson_code <= {~johnson_code[0], johnson_code[2:1]};
end

endmodule
